(7944, '', '', '', 'Ingenieurskunst ist einfach, wenn man erst einmal die Grundlagen beherrscht.', '', '', '', '', 'В инженерном деле главное - понять основы. Остальное само придет.'),
(7946, 'I can teach you how to use a fishing pole to catch fish.', '', '', 'Ich kann Euch zeigen, wie man mit einer Angelrute Fische fängt.', '', '', 'Puedo enseñarte a usar una caña de pescar para pescar.', '', 'Я могу научить тебя ловить рыбу.'),
(7948, 'With alchemy you can turn found herbs into healing and other types of potions.', '', '', 'Durch Alchemie verwandelt Ihr Käuter in Tränke.', '', '', 'Con la alquimia puedes convertir hierbas encontradas en pociones curativas y de otros tipos.', '', 'Освоив алхимию, ты сможешь варить зелья из найденных растений.'),
(7949, 'Enchanting is the art of improving existing items through magic. ', '', '', 'Verzaubern ist die Kunst, Gegenstände durch Magie zu verbessern.', '', '', 'El encantamiento es el arte de mejorar los objetos existentes mediante la magia.', '', 'Наложение чар - это искусство улучшения материальных объектов с помощью магии.'),
(7953, '', '', '', 'Hallo! Kann ich Euch etwas beibringen?', '', '', '', '', 'Здравствуйте! Могу ли я вас чему-то обучить?');
INSERT INTO `npc_trainer_greeting` (`entry`, `content_default`, `content_loc1`, `content_loc2`, `content_loc3`, `content_loc4`, `content_loc5`, `content_loc6`, `content_loc7`, `content_loc8`) VALUES
(7954, '', '', '', 'Hallo! Kann ich Euch etwas beibringen?', '', '', '', '', 'Здравствуйте! Могу ли я вас чему-то обучить?'),
(8126, 'Engineering is very simple once you grasp the basics.', '', '', 'Ingenieurskunst ist einfach, wenn man erst einmal die Grundlagen beherrscht.', '', '', 'La ingeniería es muy sencilla una vez que se comprenden sus fundamentos.', '', 'В инженерном деле главное - понять основы. Остальное само придет.'),
(8128, 'You have not lived until you have dug deep into the earth.', '', '', 'Du hast nicht gelebt, wenn du dich nicht tief in die Erde gegraben hast.', '', '', 'No has vivido hasta que no has cavado profundamente en la tierra.', '', 'Кто никогда не рылся в земле, тот, считай, и не жил!'),
(8140, 'Hello, paladin!  Ready for some training?', '', '', 'Hallo Paladin! Wollt Ihr ein bisschen üben?', '', '', '¡Hola, paladín!  ¿Listo para entrenar?', '', 'Привет тебе, паладин! Ты $gпришел:пришла; за знаниями?'),
(8141, 'Hello, warrior!  Ready for some training?', '', '', 'Hallo $GKrieger:Kriegerin;! Wollt Ihr ein bisschen üben?', '', '', '¡Hola, guerrero!  ¿Listo para entrenar?', '', 'Привет тебе, воин! Ты хочешь учиться?'),
(8142, 'Hello, druid!  Ready for some training?', '', '', 'Hallo $GDruide:Druidin;! Wollt Ihr ein bisschen üben?', '', '', '¡Hola, druida!  ¿Listo para entrenar?', '', 'Приветствую тебя, друид! Тебе нужны новые знания?'),
(8144, 'It requires a steady hand to remove the leather from a slain beast.', '', '', 'Es erfordert eine ruhige Hand, das Leder von einem erlegten Tier zu entfernen.', '', '', 'Se necesita una mano firme para quitar el cuero de una bestia muerta.', '', 'Чтобы снять шкуру с убитого зверя, нужна твердая рука.'),
(8146, 'Searching for herbs requires both knowledge and instinct.', '', '', 'Das Pflücken von Kräutern erfordert sowohl Wissen als auch Instinkt.', '', '', 'La búsqueda de hierbas requiere tanto conocimientos como instinto.', '', 'Чтобы разбираться в травах, нужны и знания, и чутье.'),
(8153, 'Greetings!  Can I teach you how to turn beast hides into armor?', '', '', 'Seid gegrüßt! Darf ich Euch lehren, wie man Tierhäute in Rüstungen verwandelt?', '', '', '¡Saludos!  ¿Puedo enseñarte a convertir pieles de bestia en armaduras?', '', 'Здравствуй! Хочешь научиться делать доспехи из шкур животных?'),
(8306, 'Can I teach you how to turn the meat you find on beasts into a feast?', '', '', 'Ich kann Euch lehren, wie Ihr aus Fleisch von Tieren ein Festmahl bereitet.', '', '', '¿Puedo enseñarte a convertir la carne que encuentras en las bestias en un festín?', '', 'Хочешь, научу, как устроить из добычи настоящее пиршество?'),
(8308, 'Hello, hunter!  Ready for some training?', '', '', 'Hallo $GJäger:Jägerin;! Wollt Ihr ein bisschen üben?', '', '', '¡Hola, cazador!  ¿Listo para entrenar?', '', 'Привет, $gохотник:охотница;! Ну что, будешь учиться?'),
(8736, 'Engineering is very simple once you grasp the basics.', '', '', 'Ingenieurskunst ist einfach, wenn man erst einmal die Grundlagen beherrscht.', '', '', 'La ingeniería es muy sencilla una vez que se comprenden sus fundamentos.', '', 'В инженерном деле главное - понять основы. Остальное само придет.'),
